var t = msg.payload.type;
if (t === 'uid')   return [msg, null, null];
if (t === 'state') return [null, msg, null];
if (t === 'ready') return [null, null, msg];
return [null, null, null];

var wl = flow.get('whitelist');
if (!wl) { wl = ['4C8A285D']; flow.set('whitelist', wl); }
var uid = (msg.payload.uid || '').toUpperCase().trim();
var authorized = wl.indexOf(uid) !== -1;
var now = new Date();
var ts = now.toLocaleTimeString('en-GB', {hour:'2-digit',minute:'2-digit',second:'2-digit'});
var entry = {ts: ts, uid: uid, ok: authorized, epoch: now.getTime()};
var history = flow.get('history') || [];
history.unshift(entry);
if (history.length > 20) history = history.slice(0, 20);
flow.set('history', history);
var counts = flow.get('counts') || {total:0, auth:0, denied:0};
counts.total = (counts.total || 0) + 1;
if (authorized) { counts.auth = (counts.auth || 0) + 1; } else { counts.denied = (counts.denied || 0) + 1; }
flow.set('counts', counts);
flow.set('lastUID', uid);
flow.set('lastVerdict', authorized ? 'AUTHORIZED' : 'DENIED');
flow.set('lastTs', ts);
var cmd = authorized ? 'open' : 'alarm';
var cmdMsg = {topic: 'GUID/commands', payload: cmd};
var statsMsg = {payload: {history: history, counts: counts, lastUID: uid, lastVerdict: authorized ? 'AUTHORIZED' : 'DENIED', lastTs: ts}};
return [cmdMsg, statsMsg];

var d = msg.payload;
var counts = d.counts;
var history = d.history;
var lastUID = d.lastUID;
var lastVerdict = d.lastVerdict;
var lastTs = d.lastTs;
var msg1 = {payload: counts.total};
var msg2 = {payload: counts.auth};
var msg3 = {payload: counts.denied};
var msg4 = {payload: {uid: lastUID, verdict: lastVerdict, ts: lastTs}};
var msg5 = {payload: history};
var now = Date.now();
var bucket = Math.floor(now / 60000);
var scanBuckets = flow.get('scanBuckets') || {};
scanBuckets[bucket] = (scanBuckets[bucket] || 0) + 1;
var cutoff = bucket - 15;
var keys = Object.keys(scanBuckets).map(Number);
keys.forEach(function(k){ if (k < cutoff) { delete scanBuckets[k]; } });
flow.set('scanBuckets', scanBuckets);
var chartPoints = [];
for (var i = 14; i >= 0; i--) {
  var b = bucket - i;
  var label = (14 - i) + 'm';
  chartPoints.push({x: label, y: scanBuckets[b] || 0});
}
var msg6 = {topic: 'Scans/min', payload: chartPoints.map(function(p){ return p.y; })};
return [msg1, msg2, msg3, msg4, msg5, msg6];

var state = (msg.payload.state || 'LOCKED').toUpperCase();
flow.set('doorState', state);
msg.payload = state;
return msg;

var uid = (flow.get('wl_pending_uid') || '').toUpperCase().trim();
var wl = flow.get('whitelist') || ['4C8A285D'];
if (!uid) {
  msg.payload = wl;
  return msg;
}
if (msg.payload === 'add' && wl.indexOf(uid) === -1) {
  wl.push(uid);
}
if (msg.payload === 'remove') {
  wl = wl.filter(function(x){ return x !== uid; });
}
flow.set('whitelist', wl);
msg.payload = wl;
return msg;

if (!flow.get('whitelist')) { flow.set('whitelist', ['4C8A285D']); }
if (!flow.get('counts')) { flow.set('counts', {total:0, auth:0, denied:0}); }
if (!flow.get('history')) { flow.set('history', []); }
if (!flow.get('scanBuckets')) { flow.set('scanBuckets', {}); }
var wl = flow.get('whitelist');
return {payload: wl};
